-- {"operators": "OUTER_JOIN,AGGREGATE,ORDER,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": true, "has_cast": false, "has_case": false, "tables": "ITEM,STOCK,ORDER_LINE", "ducklake": true}
WITH item_sales AS (SELECT ol.OL_I_ID, ol.OL_SUPPLY_W_ID, SUM(ol.OL_QUANTITY) AS qty, SUM(ol.OL_AMOUNT) AS amt FROM dl.ORDER_LINE ol GROUP BY ol.OL_I_ID, ol.OL_SUPPLY_W_ID) SELECT i.I_ID, i.I_NAME, s.S_W_ID, s.S_QUANTITY, isa.qty, DENSE_RANK() OVER (PARTITION BY s.S_W_ID ORDER BY isa.qty DESC NULLS LAST) AS top_selling FROM dl.ITEM i JOIN dl.STOCK s ON i.I_ID = s.S_I_ID LEFT JOIN item_sales isa ON s.S_I_ID = isa.OL_I_ID AND s.S_W_ID = isa.OL_SUPPLY_W_ID;
